def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 2:
            for k in range(1, int(np.ceil(ratio))+1):
                if k % 2 == 0:
                    score += (ratio / k) ** 2
                else:
                    score -= (ratio / k) ** 3
            priorities[i] = abs(score) * 5
        elif 1 < ratio <= 2:
            for m in range(1, 4):
                score += ((-1) ** m) * np.log1p(ratio * m)
            if ratio > 1.5:
                priorities[i] = abs(score) ** 2
            else:
                priorities[i] = abs(score)
        elif 0 < ratio <= 1:
            for n in range(1, 6):
                score += ((-1)**n) * (ratio**n) / n
            if ratio < 0.3:
                priorities[i] = abs(score) * 15
            elif ratio < 0.7:
                priorities[i] = abs(score) * 5
            else:
                priorities[i] = abs(score)
        else:
            priorities[i] = 0
    return priorities
